import re
from typing import List

SKU_PATTERN = re.compile(r'^[A-Z0-9][A-Z0-9\-]{2,19}$')


class ProductValidator:
    def validate(self, data: dict) -> List[str]:
        errors = []
        if not data.get('name'):
            errors.append('Product name is required')
        sku = data.get('sku', '')
        if not sku or not SKU_PATTERN.match(sku):
            errors.append('SKU must be 3-20 uppercase alphanumeric characters or dashes')
        if not isinstance(data.get('price'), (int, float)) or data['price'] < 0:
            errors.append('Price must be a non-negative number')
        if not isinstance(data.get('quantity'), int) or data['quantity'] < 0:
            errors.append('Quantity must be a non-negative integer')
        return errors
